import{_ as t,o,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Answering the Google Play Store Privacy Questions","description":"","frontmatter":{"title":"Answering the Google Play Store Privacy Questions","slug":"answering-the-google-play-store-privacy-questions"},"headers":[],"relativePath":"developer-hub/answering-the-google-play-store-privacy-questions.md","filePath":"developer-hub/answering-the-google-play-store-privacy-questions.md"}'),n={name:"developer-hub/answering-the-google-play-store-privacy-questions.md"};function s(i,e,l,d,c,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block"><p class="custom-block-title">New Safety Section Timeline</p><p>Google has informed developers that all Google Play Store submissions with the new safety section information, <strong>must be approved by April 2022</strong>.</p><p>We encourage you to submit your information early so you can get review feedback and make any necessary changes before you are no longer able to make new app updates.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>As part of the <a href="https://support.google.com/googleplay/android-developer/answer/10787469?hl=en#what_users_will_see&amp;timeline&amp;collection&amp;sharing&amp;collection_handling&amp;families&amp;independent_security_review&amp;types&amp;data_purposes&amp;understand_format&amp;export_to&amp;import_from&amp;SDK_format&amp;zippy=%2Cdata-collection%2Cwhat-users-will-see%2Ctimeline-information%2Cdata-sharing%2Cdata-handling%2Cother-app-and-data-disclosures%2Ccommitted-to-follow-the-families-policy-available-soon-to-applicable-apps%2Cindependent-security-review-optional-feature-available-soon%2Cdata-types%2Cpurposes%2Cunderstand-the-csv-format%2Cexport-to-a-csv-file%2Cimport-from-a-csv-file%2Coptional-format-for-sdks" target="_blank" rel="noreferrer">Google Play Store Developer submission process</a>, developers are required to fill out Google’s updated Data Safety section in the Google Play Console. When completing the Safety Section portion of your developer application, you are required to provide information about your app’s data collection and privacy practices, including the practices of third-party partners like Branch whose SDK code you integrate into your app.</p><p>After February 2022, “No information available” will be shown by Google in the Data Safety section for apps that have not submitted information in the Google Play Console for review and for apps that have submitted information but the submission was rejected.</p><p>Without an approval in the Data Safety section, your new app submission or app update may be rejected.</p><h2 id="answering-the-google-play-store-safety-section-questions" tabindex="-1">Answering the Google Play Store Safety Section Questions <a class="header-anchor" href="#answering-the-google-play-store-safety-section-questions" aria-label="Permalink to &quot;Answering the Google Play Store Safety Section Questions&quot;">​</a></h2><p>You must select answers from the options presented in Google Play Store. Please keep in mind:</p><ul><li>Branch’s SDKs are fully configurable by you, both in the data we collect on your behalf and how you use that data. Accordingly, you should identify all possible data collections and uses, even if not outlined here or even if certain data will be collected and used only in limited situations.</li><li>Your answers should follow the <a href="https://support.google.com/googleplay/android-developer/answer/10787469?hl=en#what_users_will_see&amp;timeline&amp;collection&amp;sharing&amp;collection_handling&amp;families&amp;independent_security_review&amp;types&amp;data_purposes&amp;understand_format&amp;export_to&amp;import_from&amp;SDK_format&amp;zippy=%2Cdata-collection%2Cwhat-users-will-see%2Ctimeline-information%2Cdata-sharing%2Cdata-handling%2Cother-app-and-data-disclosures%2Ccommitted-to-follow-the-families-policy-available-soon-to-applicable-apps%2Cindependent-security-review-optional-feature-available-soon%2Cdata-types%2Cpurposes%2Cunderstand-the-csv-format%2Cexport-to-a-csv-file%2Cimport-from-a-csv-file%2Coptional-format-for-sdks" target="_blank" rel="noreferrer">Google Play Store Safety Section Review Guidelines</a> and any applicable laws.</li><li>We encourage you to consult with your legal counsel if you have questions about compliance with applicable laws or how your use of Branch implicates applicable laws.</li><li>You are solely responsible for keeping your responses accurate and up to date. If your practices change, update your responses in Google Play Store.</li></ul><h2 id="what-you-need-to-disclose" tabindex="-1">What You Need To Disclose <a class="header-anchor" href="#what-you-need-to-disclose" aria-label="Permalink to &quot;What You Need To Disclose&quot;">​</a></h2><ul><li>Any of the required user data types that are collected and/or shared</li><li>Any user data sent off the user’s device by libraries or SDKs used in your app, regardless of whether this information is transmitted to you (the developer) or a third party</li><li>Any user data transferred from your server to a third party or transferred to another third-party app on the same device</li><li>Any user data collected or transferred through a webview which can be opened from your app, unless users are navigating the open web</li></ul><p><strong>*Note: you can learn more about each of these types of data use during the application submission process.</strong></p><h2 id="sample-answers-for-google-s-data-safety-section-for-branch-sdks" tabindex="-1">Sample Answers for Google’s Data Safety Section for Branch SDKs <a class="header-anchor" href="#sample-answers-for-google-s-data-safety-section-for-branch-sdks" aria-label="Permalink to &quot;Sample Answers for Google’s Data Safety Section for Branch SDKs&quot;">​</a></h2><h3 id="data-collection-and-security" tabindex="-1">Data Collection and Security <a class="header-anchor" href="#data-collection-and-security" aria-label="Permalink to &quot;Data Collection and Security&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Question</th><th>Answer</th></tr></thead><tbody><tr><td>Does your app collect any user data that is sent off the user&#39;s device?</td><td><strong>YES</strong> (as part of your use of the Branch Services, the Branch SDK will pass the data listed below, as further disclosed in the <a href="https://branch.io/policies/#privacy" target="_blank" rel="noreferrer">Branch Privacy Policy</a>)</td></tr><tr><td>Is this data encrypted in transit?</td><td><strong>YES</strong></td></tr><tr><td>Can users request to delete this data?</td><td><strong>YES</strong></td></tr></tbody></table><h3 id="data-types-collected-by-branch-s-sdks" tabindex="-1">Data Types Collected by Branch&#39;s SDKs <a class="header-anchor" href="#data-types-collected-by-branch-s-sdks" aria-label="Permalink to &quot;Data Types Collected by Branch&#39;s SDKs&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Prominent Disclosure and Consent</p><p>In addition to reviewing the information below, you are also responsible for ensuring your continued compliance with <a href="https://support.google.com/googleplay/android-developer/answer/11150561?hl=en" target="_blank" rel="noreferrer">Google’s Prominent Disclosure and Consent Requirements</a>.</p></div><p>You’ll need to confirm the types of data that you and/or your third-party partners including Branch collect from your app before answering the questions in Google Play Store.</p><p>Branch has provided a list of data types below that our services collect as further disclosed in our <a href="https://branch.io/policies/#privacy" target="_blank" rel="noreferrer">Privacy Policy</a>. However, you will need to compare them to your custom configuration of the Branch SDKs and the data collection practices in your app to confirm whether your answers are accurate. Please also refer to <a href="./best-practices-to-avoid-sending-pii-to-branch.html">Best Practices On How to Avoid Sending Branch PII</a>.</p><table tabindex="0"><thead><tr><th>Data Type</th><th>Collected?</th></tr></thead><tbody><tr><td>Location</td><td>- Approximate Location: <strong>NO</strong> - Precise Location: <strong>NO</strong></td></tr><tr><td>Personal Information</td><td>- Name: <strong>NO</strong> - Email Address: <strong>NO</strong> - Personal Identifiers: <strong>NO</strong> - Address: <strong>NO</strong> - Phone Number: <strong>NO</strong> - Race and Ethnicity: <strong>NO</strong> - Political or Religious Beliefs: <strong>NO</strong> - Sexual Orientation: <strong>NO</strong> - Other Personal Information: <strong>NO</strong></td></tr><tr><td>Financial Information</td><td>- Credit/Debit Card/Bank Number: <strong>NO</strong> - Purchase History: <strong>NO</strong> - Credit Information: <strong>NO</strong> - Other Financial Information: <strong>NO</strong></td></tr><tr><td>Health and Fitness</td><td>- Health Information: <strong>NO</strong> - Fitness Information: <strong>NO</strong></td></tr><tr><td>Messages</td><td>- Emails: <strong>NO</strong> - SMS or MMS: <strong>NO</strong> - Other in-app messages: <strong>NO</strong> - Photos or Videos: <strong>NO</strong></td></tr><tr><td>Audio Files</td><td>- Voice or Sound Recordings: <strong>NO</strong> - Music Files: <strong>NO</strong> - Other Audio Files: <strong>NO</strong></td></tr><tr><td>Files and Docs</td><td><strong>NO</strong></td></tr><tr><td>Calendar</td><td><strong>NO</strong></td></tr><tr><td>Contacts</td><td><strong>NO</strong></td></tr><tr><td>App Activity</td><td>- Page Views and Taps in App: <strong>YES</strong> (<strong>OPTIONAL</strong> - You can use Branch&#39;s SDK privacy controls to prevent data collection by default until the end-user opted in) - In-App Search History: <strong>NO</strong> - Installed Apps: <strong>NO</strong> - Other User-Generated Content: <strong>OPTIONAL</strong>, if we are measuring in-app purchases for you for instance - Other Actions: <strong>OPTIONAL</strong>, Branch can collect this data on your behalf (i.e. clicks, installs, purchases)</td></tr><tr><td>Web Browsing History</td><td><strong>YES</strong> (<strong>OPTIONAL</strong>)</td></tr><tr><td>App Info and Performance</td><td>- Crash Logs: <strong>NO</strong> - Diagnostics: <strong>NO</strong> - Other App Performance Data: <strong>NO</strong></td></tr><tr><td>Device or Other Identifiers</td><td><strong>YES</strong> (<strong>OPTIONAL</strong>)</td></tr><tr><td>Other Data</td><td><strong>YES</strong> (<strong>OPTIONAL</strong> - <em>Branch collects this data on your behalf (e.g. engagement data and device metadata features such as screen size and operating system version</em>)</td></tr></tbody></table><h3 id="data-usage-and-handling-by-branch-s-sdks" tabindex="-1">Data Usage and Handling by Branch&#39;s SDKs <a class="header-anchor" href="#data-usage-and-handling-by-branch-s-sdks" aria-label="Permalink to &quot;Data Usage and Handling by Branch&#39;s SDKs&quot;">​</a></h3><p>You will need to have a clear understanding of how each data type is used by you and your third-party partners including Branch. Branch provides deep linking and attribution analytics services. Depending on the type of data being collected, you may be prompted to provide more information about Branch SDKs will use and handle your data:</p><table tabindex="0"><thead><tr><th>Question</th><th>Answer</th></tr></thead><tbody><tr><td>Is data Collected and/or Shared</td><td><strong>YES</strong> to both</td></tr><tr><td>Is data “processed ephemerally”?</td><td><strong>NO</strong> (see Play Store Safety Section for definition)</td></tr><tr><td>Is the collection of data necessary to the use of the app or can users choose whether data is collected?</td><td>Users can choose to turn off this data collection (See: <a href="./honoring-opt-out-of-processing-requests.html"><em>Restricting End User Data Processing</em></a>)</td></tr><tr><td>Why is the user data collected?</td><td>- App Functionality: <strong>YES</strong> - Analytics: <strong>YES</strong> - Developer Communications: <strong>NO</strong> - Fraud Prevention, Security, or Compliance: <strong>NO</strong> - Advertising or Marketing: <strong>YES</strong> - (Product) Personalization: <strong>YES</strong> - Account Management: <strong>NO</strong></td></tr></tbody></table><h2 id="privacy-links" tabindex="-1">Privacy Links <a class="header-anchor" href="#privacy-links" aria-label="Permalink to &quot;Privacy Links&quot;">​</a></h2><p>You will have the ability to add links on your product page to your app’s privacy policy and your privacy choices documentation.</p><p>To learn more about Branch’s privacy practices and end user options, please see Branch’s Privacy Policy <a href="https://branch.io/policies/#privacy" target="_blank" rel="noreferrer">accessible here</a>.</p>',25)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
